diagnostics_hook:
#!/bin/bash
INPUT=$(head -c 65536); FILE=$(printf '%s' "$INPUT" | jq -r '.tool_input.file_path // ""')
[[ "$FILE" != *.php ]] && { echo '{"decision":"approve"}'; exit 0; }
ERRORS=$(php -l "$FILE" 2>&1)
[[ "$ERRORS" != *'No syntax errors'* ]] && echo "$ERRORS" >&2
echo '{"decision":"approve"}'
